Senses Uluwatu Bali", "experiences/3/companyId": "3549", "experiences/3/companyIndustry": "Hospitality", "experiences/3/companyLink1": "https://www.linkedin.com/company/ihghotels&resorts/", "experiences/3/companyName": "IHG Hotels & Resorts", "experiences/3/companySize": "10001-0", "experiences/3/companyUrn": "urn:li:fsd_company:3549", "experiences/3/companyWebsite": "http://www.ihgplc.com", "experiences/3/employmentType": "Full-time", "experiences/3/jobDescription": "Six Senses Kaplankaya resort in Turkey is a private escape offering you and your loved ones a combination of seclusion and social community at the heart of nature. This includes our showcase 10,000 square-meter spa with pioneering wellness programming; indoor-heated pool, hydrothermal areas, hammams, state-of-the-art fitness equipment, and classes including spinning, yoga, and Pilates. Add to this multiple organic dining options, spacious outdoor venues, private beaches, a host of children’s activities and experiences to reconnect with nature and rewild your soul.", "experiences/3/jobEndedOn": "2-2024", "experiences/3/jobLocation": "Milas, Muğla, Turkey", "experiences/3/jobLocationCountry": "GB", "experiences/3/jobStartedOn": "3-2022", "experiences/3/jobStillWorking": "false", "experiences/3/logo": "https://media.licdn.com/dms/image/v2/D4E0BAQE0llq6fMNiSA/company-logo_400_400/company-logo_400_400/0/1719918902479/ihghotelsresorts_logo?e=1778112000&v=beta&t=SQmjsK2eROVCLZpbMs_TGGjQDaoKOftZi4zpFZgMWdM", "experiences/3/title": "General Manager, Six Senses Kaplankaya", "experiences/4/companyId": "19051", "experiences/4/companyIndustry": "Hospitality", "experiences/4/companyLink1": "https://www.linkedin.com/company/kempinski-hotels/", "experiences/4/companyName": "Kempinski Hotels", "experiences/4/companySize": "10001-0", "experiences/4/companyUrn": "urn:li:fsd_company:19051", "experiences/4/companyWebsite": "https://kempinski.com/", "experiences/4/employmentType": "Full-time", "experiences/4/jobDescription"